CREATE TABLE IF NOT EXISTS t_p61016064_digital_innovation_i.wb_decision_log (id SERIAL PRIMARY KEY, case_id INTEGER NOT NULL, user_id INTEGER NOT NULL, decision_type TEXT NOT NULL DEFAULT 'general', title TEXT NOT NULL, description TEXT, decided_by TEXT, next_action TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()); CREATE INDEX IF NOT EXISTS idx_wb_decisions_case ON t_p61016064_digital_innovation_i.wb_decision_log(case_id); CREATE TABLE IF NOT EXISTS t_p61016064_digital_innovation_i.wb_notes (id SERIAL PRIMARY KEY, user_id INTEGER NOT NULL, entity_type TEXT NOT NULL, entity_id INTEGER NOT NULL, content TEXT NOT NULL, is_archived BOOLEAN NOT NULL DEFAULT FALSE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()); CREATE INDEX IF NOT EXISTS idx_wb_notes_entity ON t_p61016064_digital_innovation_i.wb_notes(entity_type, entity_id);